import React from 'react';
import { useNavigate } from 'react-router-dom';

export default function LandingPage() {
  const navigate = useNavigate();

  return (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #0f2d55 0%, #1a4a7a 50%, #1a5c6e 100%)', display: 'flex', flexDirection: 'column' }}>
      {/* Navbar */}
      <nav style={{ padding: '1rem 2rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderBottom: '1px solid rgba(255,255,255,0.1)' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          <i className="bi bi-heart-pulse-fill" style={{ color: '#ef4444', fontSize: '1.5rem' }} />
          <span style={{ color: '#fff', fontWeight: 700, fontSize: '1.2rem', letterSpacing: '-0.01em' }}>MediCare EHR</span>
        </div>
        <div style={{ display: 'flex', gap: 12 }}>
          <button className="btn btn-outline-light btn-sm" onClick={() => navigate('/login')}>Login</button>
          <button className="btn btn-sm" style={{ background: '#ef4444', color: '#fff', border: 'none' }} onClick={() => navigate('/register')}>Register</button>
        </div>
      </nav>

      {/* Hero Section */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', padding: '4rem 1.5rem', textAlign: 'center' }}>
        <div style={{ background: 'rgba(239,68,68,0.15)', borderRadius: '50%', width: 90, height: 90, display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: '1.5rem', border: '2px solid rgba(239,68,68,0.4)' }}>
          <i className="bi bi-droplet-fill" style={{ fontSize: '2.5rem', color: '#ef4444' }} />
        </div>

        <h1 style={{ color: '#fff', fontSize: 'clamp(2rem, 5vw, 3.5rem)', fontWeight: 800, marginBottom: '1rem', lineHeight: 1.2 }}>
          Save Lives with<br />
          <span style={{ color: '#ef4444' }}>Every Drop</span>
        </h1>

        <p style={{ color: 'rgba(255,255,255,0.75)', fontSize: '1.1rem', maxWidth: 560, marginBottom: '2.5rem', lineHeight: 1.7 }}>
          Your blood donation can save up to 3 lives. Join thousands of donors in our community and make a difference today.
        </p>

        <div style={{ display: 'flex', gap: 16, flexWrap: 'wrap', justifyContent: 'center' }}>
          <button
            onClick={() => navigate('/donate')}
            style={{ background: '#ef4444', color: '#fff', border: 'none', borderRadius: 12, padding: '0.85rem 2.5rem', fontSize: '1.1rem', fontWeight: 700, cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 8, boxShadow: '0 4px 20px rgba(239,68,68,0.4)', transition: 'transform 0.15s' }}
            onMouseEnter={e => e.currentTarget.style.transform = 'translateY(-2px)'}
            onMouseLeave={e => e.currentTarget.style.transform = 'translateY(0)'}
          >
            <i className="bi bi-heart-fill" />
            Donate Blood
          </button>
          <button
            onClick={() => navigate('/login')}
            style={{ background: 'rgba(255,255,255,0.1)', color: '#fff', border: '1px solid rgba(255,255,255,0.3)', borderRadius: 12, padding: '0.85rem 2rem', fontSize: '1rem', fontWeight: 600, cursor: 'pointer', backdropFilter: 'blur(8px)' }}
          >
            Patient Portal
          </button>
        </div>
      </div>

      {/* Stats Bar */}
      <div style={{ background: 'rgba(0,0,0,0.25)', borderTop: '1px solid rgba(255,255,255,0.08)', padding: '1.5rem 2rem', display: 'flex', justifyContent: 'center', gap: '3rem', flexWrap: 'wrap' }}>
        {[
          { icon: 'bi-people-fill', value: '10,000+', label: 'Registered Donors' },
          { icon: 'bi-droplet-half', value: '50,000+', label: 'Units Donated' },
          { icon: 'bi-heart-pulse', value: '3 Lives', label: 'Saved Per Donation' },
        ].map(s => (
          <div key={s.label} style={{ textAlign: 'center', color: '#fff' }}>
            <i className={`bi ${s.icon}`} style={{ fontSize: '1.4rem', color: '#ef4444', display: 'block', marginBottom: 4 }} />
            <div style={{ fontWeight: 700, fontSize: '1.2rem' }}>{s.value}</div>
            <div style={{ fontSize: '0.8rem', color: 'rgba(255,255,255,0.6)' }}>{s.label}</div>
          </div>
        ))}
      </div>
    </div>
  );
}
